# ----------------------------------------------------------------------
# 6. FLASK APP
# ----------------------------------------------------------------------
app = Flask(__name__)


def get_hdi_class(value):
    if value < 0.550:
        return "Low"
    elif value < 0.700:
        return "Medium"
    elif value < 0.800:
        return "High"
    else:
        return "Very High"


@app.route("/")
def home():
    return render_template_string(HOME_HTML)


@app.route("/Prediction", methods=["POST", "GET"])
def prediction():
    return render_template_string(INDEXNEW_HTML, countries=COUNTRY_LIST)


@app.route("/Home", methods=["POST", "GET"])
def my_home():
    return render_template_string(HOME_HTML)


@app.route("/country_data/<country>")
def country_data(country):
    entry = COUNTRY_LOOKUP.get(country)
    if not entry:
        return {"error": "unknown country"}, 404
    return {
        "life_expectancy": entry["primary"][0],
        "schooling": entry["primary"][1],
        "income": entry["primary"][2],
        "secondary": entry["secondary"],
        "actual_hdi_2021": entry["actual_hdi_2021"],
    }


@app.route("/predict", methods=["POST"])
def predict():
    try:
        country = request.form.get("Country", "")
        life_expectancy = float(request.form.get("Life expectancy"))
        schooling = float(request.form.get("Mean years of schooling"))
        income = float(request.form.get("Gross national income (GNI) per capita"))
        secondary_raw = request.form.get("secondary_features", "")
        secondary_values = [float(v) for v in secondary_raw.split(",")] if secondary_raw else None

        if secondary_values is None or len(secondary_values) != 10:
            entry = COUNTRY_LOOKUP.get(country)
            if entry is None:
                return render_template_string(
                    RESULTNEW_HTML,
                    prediction_text="Please select a valid country from the dropdown."
                )
            secondary_values = entry["secondary"]

        x = np.array([[life_expectancy, schooling, income] + secondary_values], dtype=np.float32)
        x_t = torch.tensor(x, dtype=torch.float32)
        x_scaled = (x_t - X_MIN) / (X_MAX - X_MIN)

        x_p = x_scaled[:, :N_PRIMARY]
        x_s = x_scaled[:, N_PRIMARY:]

        with torch.no_grad():
            output = model(x_p, x_s)

        y_pred = round(float(output[0][0]), 3)
        tier = get_hdi_class(y_pred)

        return render_template_string(RESULTNEW_HTML, prediction_text=f"{tier} HDI {y_pred}")

    except (TypeError, ValueError):
        return render_template_string(
            RESULTNEW_HTML,
            prediction_text="The given values do not match the expected range. Please check your inputs."
        )


if __name__ == "__main__":
    port = int(os.environ.get("PORT", 5000))
    app.run(host="0.0.0.0", port=port, debug=False)
